#pragma once\\\\\n#include <cstdint>\\\\\n#include <cstddef>\\\\\n\\\\n// Simple, robust optimization: iterate explicitly, avoid complex expressions and nonstandard intrsics\\\\\nvoid matmul(const float* A, const uint32_t* B, float* C, size_t M, size_t K) {\\\\\n    for (size_t i = 0; i < M; ++i) {\\\\\n        for (size_t j = 0; j < K; ++j) {\\\\\n            float sum = 0.0f;\\\\\n            for (size_t p = 0; p < K; ++p) {\\\\\n                // Decode sign bit from packed 32-bit integer at B[p][j]\n                uint32_t bval = B[p * (K / 32) + j / 32];\\n                bool is_one = (bval >> (j % 32)) & 1u;\n                float sign = is_one ? 1.0f : -1.0f;\\n                // Multiply scalar A[i][p] by corresponding sign and accumulate\n                sum += A[i * K + p] * sign;\\\\\n            }\\\n            // Store result only once per output element\n            C[i * K + j] = sum;\\\n        }\n    }\\n}